using Npgsql; using System; class Program { static void Main() { var connString = "Host=localhost;Port=5434;Database=craftvision_db;Username=craftvision_user;Password=craftvision_password"; using var conn = new NpgsqlConnection(connString); conn.Open(); using var cmd = new NpgsqlCommand("SELECT id, name FROM products", conn); using var reader = cmd.ExecuteReader(); while (reader.Read()) { Console.WriteLine($"{reader.GetGuid(0)} | {reader.GetString(1)}"); } } }
